package net.evarius.terranexus.landlord;
import com.mojang.serialization.Codec;import com.mojang.serialization.codecs.RecordCodecBuilder;import net.minecraft.datafixer.DataFixTypes;import net.minecraft.server.MinecraftServer;import net.minecraft.world.PersistentState;import net.minecraft.world.PersistentStateType;import java.util.*;
public class LandAuditState extends PersistentState {private static final Codec<LandAuditState> CODEC=RecordCodecBuilder.create(i->i.group(LandAuditEntry.CODEC.listOf().optionalFieldOf("entries",List.of()).forGetter(s->s.entries),OwnershipChange.CODEC.listOf().optionalFieldOf("ownership",List.of()).forGetter(s->s.ownership)).apply(i,LandAuditState::new));private static final PersistentStateType<LandAuditState> TYPE=new PersistentStateType<>("terranexus_land_audit",LandAuditState::new,CODEC,DataFixTypes.LEVEL);private final List<LandAuditEntry> entries;private final List<OwnershipChange> ownership;public LandAuditState(){this(new ArrayList<>(),new ArrayList<>());}private LandAuditState(List<LandAuditEntry> e,List<OwnershipChange> o){entries=new ArrayList<>(e);ownership=new ArrayList<>(o);}public static LandAuditState get(MinecraftServer s){return s.getOverworld().getPersistentStateManager().getOrCreate(TYPE);}public void log(UUID actor,String action,LandProperty property,String details){entries.add(new LandAuditEntry(System.currentTimeMillis(),actor.toString(),action,property.id(),details));trim(entries);markDirty();}public void owner(UUID actor,LandProperty old,String newType,String newId){ownership.add(new OwnershipChange(System.currentTimeMillis(),actor.toString(),old.id(),old.ownerType(),old.ownerId(),newType,newId));trim(ownership);log(actor,"OWNER_CHANGE",old,old.ownerType()+":"+old.ownerId()+" -> "+newType+":"+newId);}public List<LandAuditEntry> recent(){int from=Math.max(0,entries.size()-45);List<LandAuditEntry> result=new ArrayList<>(entries.subList(from,entries.size()));Collections.reverse(result);return result;}public List<OwnershipChange> history(String propertyId){return ownership.stream().filter(x->x.propertyId().equals(propertyId)).sorted(Comparator.comparingLong(OwnershipChange::timestamp).reversed()).toList();}private static void trim(List<?> list){if(list.size()>2000)list.subList(0,list.size()-2000).clear();}}
